/* ============================================================
   SUPABASE-BACKED STORAGE LAYER
   ------------------------------------------------------------
   Replaces window.storage (artifact-only, unreliable) with a real
   Postgres database via Supabase's REST API. Every function below
   keeps the EXACT same name, signature, and return shape as before
   (storeGet, storeSet, storeSetVerbose, storeDelete, storeListPrefix),
   so nothing anywhere else in this file needs to change — every page,
   form, and Admin action calls these exactly as it always has.

   SETUP: paste your Project URL and anon/public key below. Never put
   a service-role/secret key here — this file is public client-side
   code, and the anon key is specifically designed to be safe to expose
   (Row Level Security in Supabase is the actual protection boundary).
   ============================================================ */
const SUPABASE_URL = "https://ciezdtpuletwnqjzbehj.supabase.co";
const SUPABASE_ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNpZXpkdHB1bGV0d25xanpiZWhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODMyODk2OTUsImV4cCI6MjA5ODg2NTY5NX0.enbbxk8LSbBZ0q10soraOTO66KmKBie69uyVUcZXbhI";

/* Maps the app's existing key prefixes (e.g. "prayer:", "events:") to
   real Supabase table names. "settings" (no colon) is a single-row table. */
const TABLE_MAP = {
  prayer: "prayer_requests",
  join: "join_submissions",
  rsvp: "rsvps",
  events: "events",
  posts: "teachings",
  recaps: "recaps",
  decision: "decisions",
};
const SETTINGS_ROW_ID = "main";

function resolveTableAndId(key) {
  if (key === "settings") return { table: "settings", id: SETTINGS_ROW_ID };
  const idx = key.indexOf(":");
  if (idx === -1) return null;
  const prefix = key.slice(0, idx);
  const id = key.slice(idx + 1);
  const table = TABLE_MAP[prefix];
  if (!table) return null;
  return { table, id };
}

async function supabaseFetch(path, options = {}) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    ...options,
    headers: {
      apikey: SUPABASE_ANON_KEY,
      Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
      "Content-Type": "application/json",
      ...(options.headers || {}),
    },
  });
  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`Supabase ${res.status}: ${text || res.statusText}`);
  }
  if (res.status === 204) return null;
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

/* Retries a flaky request before giving up — protects against transient
   network hiccups self-resolving on a near-immediate second attempt. */
async function withRetry(fn, attempts = 2, delayMs = 500) {
  let lastError = null;
  for (let i = 0; i < attempts; i++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      if (i < attempts - 1) {
        await new Promise((resolve) => setTimeout(resolve, delayMs));
      }
    }
  }
  throw lastError;
}

/* One-shot cache populated by storeListPrefix so the common "list then
   fetch each" pattern used throughout Admin doesn't cost N+1 network
   requests — invisible to every caller, pure internal optimization. */
const _rowCache = {};

async function storeGet(key, shared = true) {
  try {
    if (_rowCache[key]) {
      const cached = _rowCache[key];
      delete _rowCache[key];
      return cached;
    }
    const resolved = resolveTableAndId(key);
    if (!resolved) return null;
    const rows = await withRetry(() =>
      supabaseFetch(`${resolved.table}?id=eq.${encodeURIComponent(resolved.id)}&select=*`)
    );
    if (!rows || rows.length === 0) return null;
    return rows[0];
  } catch {
    return null;
  }
}

async function upsertRecord(key, value) {
  const resolved = resolveTableAndId(key);
  if (!resolved) throw new Error(`Unknown storage key: ${key}`);
  const payload = { ...value, id: resolved.id };
  await supabaseFetch(`${resolved.table}?on_conflict=id`, {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify(payload),
  });
}

async function storeSet(key, value, shared = true) {
  try {
    await withRetry(() => upsertRecord(key, value));
    return true;
  } catch {
    return false;
  }
}
/* Verbose variant used only in Admin save flows, so failures show the real
   reason instead of a generic message. storeSet above is left untouched
   since Prayer, Join, RSVP, and app init all depend on its plain boolean. */
async function storeSetVerbose(key, value, shared = true) {
  try {
    await withRetry(() => upsertRecord(key, value));
    return { ok: true, error: null };
  } catch (err) {
    const message = (err && (err.message || err.toString())) || "Unknown error";
    return { ok: false, error: message };
  }
}
async function storeDelete(key, shared = true) {
  try {
    const resolved = resolveTableAndId(key);
    if (!resolved) return false;
    await withRetry(() =>
      supabaseFetch(`${resolved.table}?id=eq.${encodeURIComponent(resolved.id)}`, {
        method: "DELETE",
        headers: { Prefer: "return=minimal" },
      })
    );
    return true;
  } catch {
    return false;
  }
}
async function storeListPrefix(prefix, shared = true) {
  try {
    const cleanPrefix = prefix.endsWith(":") ? prefix.slice(0, -1) : prefix;
    const table = TABLE_MAP[cleanPrefix];
    if (!table) return [];
    const rows = await withRetry(() => supabaseFetch(`${table}?select=*`));
    const keys = [];
    for (const row of rows || []) {
      const key = `${cleanPrefix}:${row.id}`;
      _rowCache[key] = row;
      keys.push(key);
    }
    return keys;
  } catch {
    return [];
  }
}
function newId() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
}

