function NeedCard({ emoji, iconName, bg, title, onClick, textColor = COLORS.evergreenDeep }) {
  const tap = useTapScale();
  return (
    <button
      {...tap}
      onClick={() => {
        buzz();
        onClick();
      }}
      style={{
        background: bg,
        border: "none",
        borderRadius: 22,
        padding: "20px 16px",
        cursor: "pointer",
        display: "flex",
        flexDirection: "column",
        alignItems: "flex-start",
        gap: 10,
        textAlign: "left",
        boxShadow: SHADOW.card,
        ...tap.style,
      }}
    >
      {iconName ? (
        <Icon name={iconName} size={26} color={textColor} />
      ) : (
        <span style={{ fontSize: 24 }}>{emoji}</span>
      )}
      <span style={{ fontFamily: FONTS.body, fontWeight: 700, fontSize: 14.5, color: textColor, lineHeight: 1.35 }}>{title}</span>
    </button>
  );
}

function NextStepCard() {
  const todayKey = NEXT_STEP_KEY_PREFIX + new Date().toDateString();
  const [done, setDone] = useState(false);
  const step = nextSteps[dayIndex(nextSteps.length)];

  useEffect(() => {
    try {
      setDone(window.localStorage.getItem(todayKey) === "true");
    } catch {
      /* localStorage unavailable — completion just won't persist */
    }
  }, [todayKey]);

  const markDone = () => {
    buzz();
    try {
      window.localStorage.setItem(todayKey, "true");
    } catch {
      /* no-op */
    }
    setDone(true);
  };

  return (
    <Card style={{ background: COLORS.evergreen }}>
      <Eyebrow color={COLORS.goldSoft}>Today's Next Step</Eyebrow>
      <p style={{ fontFamily: FONTS.body, fontSize: 16, lineHeight: 1.6, color: COLORS.white, margin: "0 0 16px" }}>
        {step}
      </p>
      {done ? (
        <span style={{ fontFamily: FONTS.body, fontWeight: 700, fontSize: 14, color: COLORS.goldSoft }}>✓ Completed today</span>
      ) : (
        <Button variant="gold" size="sm" onClick={markDone}>Mark as Done</Button>
      )}
    </Card>
  );
}

