function PrayerPage() {
  const [form, setForm] = useState({ name: "", contact: "", request: "", shareable: true, urgent: false });
  const [submitted, setSubmitted] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  const submit = async (e) => {
    e.preventDefault();
    if (!form.name.trim() || !form.request.trim()) {
      setError("Please share your name and your prayer request.");
      return;
    }
    setError("");
    setSaving(true);
    const id = newId();
    const record = { id, ...form, date: new Date().toISOString() };
    const ok = await storeSet(`prayer:${id}`, record, true);
    setSaving(false);
    if (ok) {
      setSubmitted(true);
      /* ---- EMAIL NOTIFICATION HOOK ----
         When you set up an email service (e.g. EmailJS, Formspree), call it here with `record`.
         Example (EmailJS): await emailjs.send('service_id','template_id',record,'public_key'); */
    } else {
      setError("Something went wrong submitting your request. Please try again.");
    }
  };

  if (submitted) {
    return (
      <div style={{ maxWidth: 540, margin: "0 auto", padding: "50px 20px 60px" }}>
        <ConfirmBanner>You don't have to carry this alone. Your request has been received{form.shareable ? "" : ", and it will remain private"}.</ConfirmBanner>
        <div style={{ textAlign: "center" }}>
          <Button variant="outline" onClick={() => setSubmitted(false)}>Submit Another Request</Button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 540, margin: "0 auto", padding: "36px 20px 60px" }}>
      <Eyebrow color={COLORS.peachDeep}>Need Prayer?</Eyebrow>
      <PageTitle>You don't have to carry it alone.</PageTitle>
      <p style={{ fontSize: 15, color: COLORS.charcoalSoft, margin: "16px 0 8px", lineHeight: 1.65 }}>
        We'd love to pray with you. Share as much or as little as you'd like.
      </p>
      <p style={{ fontSize: 13.5, color: COLORS.sageDeep, margin: "0 0 26px", fontWeight: 600 }}>
        Everything shared here is treated with care.
      </p>
      <Card>
        <form onSubmit={submit}>
          <Field label="Name">
            <TextInput value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Your name" />
          </Field>
          <Field label="Email or phone" hint="Optional — only if you'd like a follow-up.">
            <TextInput value={form.contact} onChange={(e) => setForm({ ...form, contact: e.target.value })} placeholder="you@example.com or (555) 555-5555" />
          </Field>
          <Field label="Prayer request">
            <TextArea value={form.request} onChange={(e) => setForm({ ...form, request: e.target.value })} placeholder="Share what's on your heart..." />
          </Field>
          <Field label="Can this be shared with the prayer team?">
            <YesNoToggle value={form.shareable} onChange={(v) => setForm({ ...form, shareable: v })} />
          </Field>
          <Field label="Is this urgent?">
            <YesNoToggle value={form.urgent} onChange={(v) => setForm({ ...form, urgent: v })} />
          </Field>
          {error && <p style={{ color: COLORS.peachDeep, fontSize: 14, marginBottom: 14 }}>{error}</p>}
          <Button type="submit" variant="primary" full disabled={saving}>{saving ? "Submitting..." : "Send Prayer Request"}</Button>
        </form>
      </Card>
    </div>
  );
}

