function fmtDate(iso, withTime = true) {
  try {
    const d = new Date(iso);
    const opts = withTime ? { weekday: "short", month: "short", day: "numeric", hour: "numeric", minute: "2-digit" } : { month: "short", day: "numeric", year: "numeric" };
    return d.toLocaleString("en-US", opts);
  } catch {
    return iso;
  }
}

/* ---------- CSV export helper (client-side only, no dependencies) ---------- */
function exportToCSV(filename, rows) {
  if (!rows || rows.length === 0) return;
  const headers = Object.keys(rows[0]);
  const escapeCell = (val) => {
    const str = val === null || val === undefined ? "" : String(val);
    if (str.includes(",") || str.includes('"') || str.includes("\n")) {
      return `"${str.replace(/"/g, '""')}"`;
    }
    return str;
  };
  const csvLines = [
    headers.join(","),
    ...rows.map((row) => headers.map((h) => escapeCell(row[h])).join(",")),
  ];
  const csvContent = csvLines.join("\n");
  const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
}

function RsvpModal({ event, onClose }) {
  const [form, setForm] = useState({ name: "", contact: "", guests: "1" });
  const [done, setDone] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const submit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");
    const id = newId();
    const ok = await storeSet(`rsvp:${id}`, { id, eventId: event.id, eventTitle: event.title, ...form, date: new Date().toISOString() }, true);
    setSaving(false);
    if (ok) {
      setDone(true);
    } else {
      setError("Something went wrong submitting your RSVP. Please check your connection and try again.");
    }
  };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(8,23,18,0.5)", display: "flex", alignItems: "center", justifyContent: "center", padding: 20, zIndex: 100 }} onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: COLORS.white, borderRadius: 26, padding: 28, maxWidth: 420, width: "100%" }}>
        {done ? (
          <div style={{ textAlign: "center" }}>
            <div style={{ fontSize: 28, marginBottom: 10 }}>✅</div>
            <div style={{ fontFamily: FONTS.heading, fontWeight: 600, fontSize: 19, marginBottom: 16, color: COLORS.evergreenDeep }}>You're on the list!</div>
            <Button variant="primary" onClick={onClose}>Close</Button>
          </div>
        ) : (
          <form onSubmit={submit}>
            <div style={{ fontFamily: FONTS.heading, fontWeight: 600, fontSize: 19, marginBottom: 4, color: COLORS.evergreenDeep }}>RSVP</div>
            <p style={{ fontSize: 13.5, color: COLORS.charcoalSoft, marginBottom: 18 }}>{event.title} — {fmtDate(event.date)}</p>
            <Field label="Name"><TextInput required value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></Field>
            <Field label="Email or phone"><TextInput required value={form.contact} onChange={(e) => setForm({ ...form, contact: e.target.value })} /></Field>
            <Field label="Number attending">
              <TextInput type="number" min="1" value={form.guests} onChange={(e) => setForm({ ...form, guests: e.target.value })} />
            </Field>
            {error && <p style={{ color: COLORS.peachDeep, fontSize: 13.5, marginBottom: 10 }}>{error}</p>}
            <div style={{ display: "flex", gap: 10, marginTop: 6 }}>
              <Button variant="outline" onClick={onClose} disabled={saving}>Cancel</Button>
              <Button type="submit" variant="primary" full disabled={saving}>{saving ? "Submitting..." : "Confirm RSVP"}</Button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
}

