                padding: "8px 14px",
                borderRadius: 999,
                border: `1.5px ${isPreviewOnly ? "dashed" : "solid"} ${seriesFilter === s ? COLORS.evergreen : COLORS.goldSoft}`,
                background: seriesFilter === s ? COLORS.evergreen : COLORS.white,
                color: seriesFilter === s ? COLORS.white : COLORS.charcoal,
