function ScripturePage() {
  const [query, setQuery] = useState("");
  const [translation, setTranslation] = useState("WEB");

  const q = query.trim().toLowerCase();
  const exactTopicMatch = SCRIPTURE_TOPICS.find((t) => t.toLowerCase() === q);
  const results = !q
    ? scriptureLibrary
    : exactTopicMatch
    ? scriptureLibrary.filter((e) => e.topic.toLowerCase() === q)
    : scriptureLibrary.filter(
        (e) =>
          e.topic.toLowerCase().includes(q) ||
          e.entries.some((v) => v.reference.toLowerCase().includes(q)) ||
          e.keywords.some((k) => k.includes(q) || q.includes(k))
      );

  return (
    <div style={{ maxWidth: 720, margin: "0 auto", padding: "36px 20px 60px" }}>
      <Eyebrow color={COLORS.gold}>Find Scripture</Eyebrow>
      <PageTitle>Find Scripture for What You're Carrying</PageTitle>
      <p style={{ fontSize: 15, color: COLORS.charcoalSoft, margin: "16px 0 6px", lineHeight: 1.65 }}>
        Search by topic and find Scripture, plain meaning, life application, and Fresh24 teaching connections.
      </p>
      <p style={{ fontSize: 12.5, color: COLORS.charcoalSoft, margin: "0 0 24px", fontStyle: "italic" }}>
        A growing, hand-picked collection by topic — not a full Bible search.
      </p>

      <div style={{ marginBottom: 16 }}>
        <TextInput
          placeholder="Search by topic, Scripture, or season..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
      </div>

      <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 28 }}>
        {SCRIPTURE_TOPICS.map((topic) => {
          const active = q === topic.toLowerCase();
          return (
            <button
              key={topic}
              onClick={() => {
                buzz();
                setQuery(active ? "" : topic);
              }}
              style={{
                padding: "8px 14px",
                borderRadius: 999,
                border: `1.5px solid ${active ? COLORS.evergreen : COLORS.goldSoft}`,
                background: active ? COLORS.evergreen : COLORS.white,
                color: active ? COLORS.white : COLORS.charcoal,
                fontFamily: FONTS.body,
                fontSize: 12.5,
                fontWeight: 600,
                cursor: "pointer",
                transition: "transform 160ms ease",
              }}
            >
              {topic}
            </button>
          );
        })}
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 28 }}>
        {["WEB", "KJV"].map((t) => (
          <button
            key={t}
            onClick={() => {
              buzz();
              setTranslation(t);
            }}
            style={{
              padding: "8px 18px",
              borderRadius: 999,
              border: `1.5px solid ${translation === t ? COLORS.evergreen : COLORS.goldSoft}`,
              background: translation === t ? COLORS.evergreen : COLORS.white,
              color: translation === t ? COLORS.white : COLORS.charcoal,
              fontFamily: FONTS.body,
              fontSize: 13,
              fontWeight: 700,
              cursor: "pointer",
              transition: "transform 160ms ease",
            }}
          >
            {t}
          </button>
        ))}
      </div>

      {results.length === 0 && (
        <p style={{ color: COLORS.charcoalSoft, fontSize: 14.5 }}>
          No matches yet — try a different word like "fear," "identity," or "money."
        </p>
      )}

      {results.map((entry) => (
        <ScriptureCard key={entry.topic} entry={entry} translation={translation} />
      ))}
    </div>
  );
}

