function DecisionForm() {
  const [form, setForm] = useState({ name: "", email: "", phone: "", decision: "" });
  const [submitted, setSubmitted] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  const DECISIONS = [
    "I accepted Jesus today.",
    "I recommitted my life to Christ.",
    "I have questions and would like someone to reach out.",
  ];

  const submit = async (e) => {
    e.preventDefault();
    if (!form.name.trim() || !form.decision) {
      setError("Please share your name and let us know which decision you're making.");
      return;
    }
    setError("");
    setSaving(true);
    const id = newId();
    const record = { id, ...form, date: new Date().toISOString() };
    const ok = await storeSet(`decision:${id}`, record, true);
    setSaving(false);
    if (ok) {
      setSubmitted(true);
    } else {
      setError("Something went wrong. Please try again.");
    }
  };

  if (submitted) {
    return (
      <ConfirmBanner title="This is just the beginning">
        Following Jesus is the start of a lifelong relationship, not the end of a moment. We're honored to walk with you. Someone from Fresh24 will be in touch soon.
      </ConfirmBanner>
    );
  }

  return (
    <Card>
      <form onSubmit={submit}>
        <Field label="Name">
          <TextInput value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} />
        </Field>
        <Field label="Email" hint="Optional">
          <TextInput type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} />
        </Field>
        <Field label="Phone" hint="Optional">
          <TextInput value={form.phone} onChange={(e) => setForm({ ...form, phone: e.target.value })} />
        </Field>
        <Field label="Which decision are you making?">
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {DECISIONS.map((d) => (
              <button
                key={d}
                type="button"
                onClick={() => {
                  buzz();
                  setForm({ ...form, decision: d });
                }}
                style={{
                  padding: "13px 16px",
                  borderRadius: 16,
                  border: `1.5px solid ${form.decision === d ? COLORS.evergreen : COLORS.goldSoft}`,
                  background: form.decision === d ? COLORS.evergreen : COLORS.white,
                  color: form.decision === d ? COLORS.white : COLORS.charcoal,
                  fontFamily: FONTS.body,
                  fontSize: 14,
                  fontWeight: 600,
                  textAlign: "left",
                  cursor: "pointer",
                  transition: "transform 160ms ease",
                }}
              >
                {d}
              </button>
            ))}
          </div>
        </Field>
        {error && <p style={{ color: COLORS.peachDeep, fontSize: 14, marginBottom: 14 }}>{error}</p>}
        <Button type="submit" variant="primary" full disabled={saving}>{saving ? "Submitting..." : "Submit"}</Button>
      </form>
    </Card>
  );
}

