function AdminEditorModal({ title, fields, initial, onSave, onClose }) {
  const [form, setForm] = useState(initial);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  const handleSave = async () => {
    setSaving(true);
    setError("");
    const result = await onSave(form);
    setSaving(false);
    if (result !== true) {
      setError(typeof result === "string" && result ? result : "Something went wrong saving this. Please check your connection and try again.");
    }
  };

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(8,23,18,0.5)", display: "flex", alignItems: "center", justifyContent: "center", padding: 20, zIndex: 100, overflowY: "auto" }} onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: COLORS.white, borderRadius: 26, padding: 28, maxWidth: 480, width: "100%", maxHeight: "90vh", overflowY: "auto" }}>
        <div style={{ fontFamily: FONTS.heading, fontWeight: 600, fontSize: 19, marginBottom: 20, color: COLORS.evergreenDeep }}>{title}</div>
        {fields.map((f) => (
          <Field key={f.key} label={f.label}>
            {f.type === "textarea" ? (
              <TextArea value={form[f.key] || ""} onChange={(e) => setForm({ ...form, [f.key]: e.target.value })} />
            ) : f.type === "select" ? (
              <select
                value={form[f.key] || ""}
                onChange={(e) => setForm({ ...form, [f.key]: e.target.value })}
                style={inputStyle}
              >
                <option value="">Select...</option>
                {f.options.map((opt) => (
                  <option key={opt} value={opt}>{opt}</option>
                ))}
              </select>
            ) : (
              <TextInput type={f.type || "text"} value={form[f.key] || ""} onChange={(e) => setForm({ ...form, [f.key]: e.target.value })} />
            )}
          </Field>
        ))}
        {error && <p style={{ color: COLORS.peachDeep, fontSize: 13.5, marginBottom: 14 }}>{error}</p>}
        <div style={{ display: "flex", gap: 10, marginTop: 6 }}>
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button variant="primary" full onClick={handleSave} disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
        </div>
      </div>
    </div>
  );
}

